import socket
from threading import Thread

# Game data, replace this with actual game state
game_state = "Game in progress"
player_list = ["Player1", "Player2"]

def handle_client(conn):
    while True:
        msg = conn.recv(4096)
        if not msg: 
            break
        
        # Server status endpoint
        if msg == b"STATUS":
            response = f"Players: {', '.join(player_list)}\nGame state: {game_state}"
            conn.sendall(response.encode())
    
    conn.close()

def server():
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.bind(("", 12345))

    while True:
        data, addr = sock.recvfrom(4096)
        
        # Set up a new thread for each client to handle multiple clients concurrently
        Thread(target=handle_client, args=(data,)).start()

if __name__ == "__main__":
    server()